from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent complex sentence.
    """
    if not triples:
        return ""

    # Find the main building subject (the one that appears most frequently as subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1

    # The main subject is the one with most triples or the first one
    main_subject = max(subject_counts, key=subject_counts.get)

    # Collect all information related to the main subject
    main_subject_triples = []
    location_info = {}
    country_info = {}
    other_info = []

    for t in triples:
        if t.subject == main_subject:
            main_subject_triples.append(t)
        elif t.predicate == 'country':
            country_info[t.subject] = t.object
        elif t.predicate in ['location', 'address', 'region', 'state']:
            location_info[t.predicate] = t.object
        elif t.predicate == 'isPartOf':
            location_info['isPartOf'] = t.object

    # Build sentence parts for the main building
    sentence_parts = []
    location_clauses = []
    additional_info = []

    # Process all triples for the main subject
    for t in main_subject_triples:
        pred = t.predicate
        obj = t.object

        if pred == 'buildingType':
            sentence_parts.append(f"{main_subject} is a {obj}")
        elif pred == 'location':
            location_clauses.append(f"located at {obj}")
        elif pred == 'address':
            location_clauses.append(f"with address {obj}")
        elif pred == 'country':
            country_info['main'] = obj
        elif pred == 'architect':
            additional_info.append(f"designed by {obj}")
        elif pred == 'architecturalStyle':
            additional_info.append(f"featuring {obj} architecture")
        elif pred == 'floorCount':
            additional_info.append(f"{obj} floors")
        elif pred == 'height':
            additional_info.append(f"{obj} in height")
        elif pred == 'cost':
            additional_info.append(f"with a cost of {obj}")
        elif pred == 'numberOfRooms':
            additional_info.append(f"{obj} rooms")
        elif pred == 'owner':
            additional_info.append(f"owned by {obj}")
        elif pred == 'developer':
            additional_info.append(f"developed by {obj}")
        elif pred == 'tenant' or pred == 'currentTenants':
            additional_info.append(f"occupied by {obj}")
        elif pred == 'yearOfConstruction':
            additional_info.append(f"built in {obj}")
        elif pred == 'completionDate':
            additional_info.append(f"completed in {obj}")
        elif pred == 'inaugurationDate':
            additional_info.append(f"inaugurated on {obj}")
        elif pred == 'formerName':
            additional_info.append(f"formerly known as {obj}")
        elif pred == 'bedCount':
            additional_info.append(f"{obj} beds")
        elif pred == 'floorArea':
            additional_info.append(f"{obj} floor area")
        elif pred == 'website':
            additional_info.append(f"website available at {obj}")
        elif pred == 'region':
            location_clauses.append(f"in {obj}")
        elif pred == 'state':
            location_clauses.append(f"in {obj}")
        elif pred == 'postalCode':
            additional_info.append(f"postal code {obj}")
        elif pred == 'leader':
            additional_info.append(f"led by {obj}")
        elif pred == 'governingBody':
            additional_info.append(f"managed by {obj}")
        elif pred == 'governmentType':
            additional_info.append(f"with {obj} government")
        elif pred == 'leaderTitle':
            additional_info.append(f"with leader title {obj}")
        elif pred == 'language':
            additional_info.append(f"with {obj}")
        elif pred == 'ethnicGroup':
            additional_info.append(f"home to {obj}")
        elif pred == 'capital':
            location_clauses.append(f"capital is {obj}")
        elif pred == 'currency':
            additional_info.append(f"using {obj}")
        elif pred == 'demonym':
            additional_info.append(f"known as {obj}")
        elif pred == 'origin':
            additional_info.append(f"originating from {obj}")
        elif pred == 'birthPlace':
            additional_info.append(f"born in {obj}")
        elif pred == 'deathPlace':
            additional_info.append(f"died in {obj}")
        elif pred == 'foundationPlace':
            additional_info.append(f"founded in {obj}")
        elif pred == 'keyPerson':
            additional_info.append(f"key person is {obj}")
        elif pred == 'significantProject':
            additional_info.append(f"significant project {obj}")
        elif pred == 'significantBuilding':
            additional_info.append(f"significant building {obj}")
        elif pred == 'architecture':
            additional_info.append(f"architecture is {obj}")
        elif pred == 'NationalRegisterOfHistoricPlacesReferenceNumber':
            additional_info.append(f"register number {obj}")
        elif pred == 'addedToTheNationalRegisterOfHistoricPlaces':
            additional_info.append(f"added to register on {obj}")
        elif pred == 'formerName':
            additional_info.append(f"formerly {obj}")

    # Process location-related triples from other subjects
    for subj, obj in country_info.items():
        if subj != main_subject:
            location_clauses.append(f"in {obj}")

    # Build the main sentence
    if not sentence_parts:
        sentence_parts.append(f"{main_subject}")

    # Add location information first
    if location_clauses:
        # Combine location clauses properly
        location_text = ", ".join(location_clauses)
        sentence_parts[0] += f", {location_text}"

    # Add additional building details
    if additional_info:
        details_text = ", ".join(additional_info)
        sentence_parts[0] += f", {details_text}"

    # Join everything and format properly
    sentence = sentence_parts[0]

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END

